ZIP_TOPOGRAMAS = IMAGES_DIR / "IMAGENES TOPOGRAMA.zip"


def _buscar_archivo_topogramas_excel():
    candidatos = [
        EXCEL_DIR / "imagenes_topograma.xlsx",
        EXCEL_DIR / "Imagenes_topograma.xlsx",
        EXCEL_DIR / "IMAGENES_TOPOGRAMA.xlsx",
        EXCEL_DIR / "topogramas.xlsx",
        BASE_DIR / "imagenes topograma.xlsx",
        BASE_DIR / "Imagenes topograma.xlsx",
        BASE_DIR / "IMAGENES TOPOGRAMA.xlsx",
        BASE_DIR / "imagenes_topograma.xlsx",
        BASE_DIR / "topogramas.xlsx",
    ]
    for c in candidatos:
        if c.exists():
            return c

    try:
        for carpeta in [EXCEL_DIR, BASE_DIR]:
            if carpeta.exists():
                for patron in ["*.xlsx", "*.xls"]:
                    for f in carpeta.glob(patron):
                        nombre = _norm_topo_texto(f.stem)
                        if "topograma" in nombre:
                            return f
    except Exception:
        pass

    return None


def _norm_topo_texto(valor):
    if valor is None:
        return ""
    s = str(valor).strip().lower()
    s = unicodedata.normalize("NFKD", s)
    s = "".join(ch for ch in s if not unicodedata.combining(ch))
    s = s.replace("°", "")
    s = s.replace("-", " ")
    s = s.replace("_", " ")
    s = " ".join(s.split())
    reemplazos = {
        "decubito": "decubito",
        "decubito supino": "decubito supino",
        "decubito prono": "decubito prono",
        "decubito lateral derecho": "decubito lateral derecho",
        "decubito lateral izquierdo": "decubito lateral izquierdo",
        "cabeza primero": "cabeza primero",
        "pies primero": "pies primero",
        "arriba 0": "arriba 0",
        "abajo 180": "abajo 180",
        "derecha 90": "derecha 90",
        "izquierda 90": "izquierda 90",
        "atc": "angiotac",
    }
    s = reemplazos.get(s, s)
    return s


def _norm_topo_examen(valor):
    s = _norm_topo_texto(valor)
    if s.startswith("atc "):
        s = s.replace("atc ", "angiotac ", 1)
    mapa = {
        "atc cerebro": "angiotac cerebro",
        "atc cuello": "angiotac cuello",
        "atc cerebro cuello": "angiotac cerebro cuello",
        "atc torax": "angiotac torax",
        "atc abdomen": "angiotac abdomen",
        "atc abdomen pelvis": "angiotac abdomen pelvis",
        "atc torax abdomen pelvis": "angiotac torax abdomen pelvis",
        "torax abdomen pelvis": "torax abdomen pelvis",
        "abdomen pelvis": "abdomen pelvis",
        "eess derecha": "angiotac extremidad superior derecha",
        "eess izquierda": "angiotac extremidad superior izquierda",
        "eeii": "angiotac extremidades inferiores",
        "pielotac": "pielotac",
    }
    return mapa.get(s, s)


@st.cache_data
def cargar_tabla_topogramas_adquiridos():
    archivo_excel = _buscar_archivo_topogramas_excel()
    if archivo_excel is None:
        return pd.DataFrame()

    try:
        df = pd.read_excel(archivo_excel)
    except Exception:
        return pd.DataFrame()

    df.columns = [str(c).strip() for c in df.columns]
    columnas_normalizadas = {_norm_topo_texto(c): c for c in df.columns}
    renombres = {}

    equivalencias = {
        "entrada del paciente": "entrada",
        "entrada": "entrada",
        "posicion paciente": "posicion_paciente",
        "paciente": "posicion_paciente",
        "posicion tubo": "pos_tubo",
        "tubo": "pos_tubo",
        "examen": "examen",
        "protocolo": "examen",
        "nombre exacto de la imagen": "nombre_imagen",
        "nombre imagen": "nombre_imagen",
        "imagen": "nombre_imagen",
    }

    for col_norm, col_real in columnas_normalizadas.items():
        destino = equivalencias.get(col_norm)
        if destino:
            renombres[col_real] = destino

    df = df.rename(columns=renombres)
    cols_necesarias = ["entrada", "posicion_paciente", "pos_tubo", "examen", "nombre_imagen"]
    for c in cols_necesarias:
        if c not in df.columns:
            return pd.DataFrame()
    df = df[cols_necesarias].copy()
    df = df.dropna(how="all")
    df["entrada_norm"] = df["entrada"].map(_norm_topo_texto)
    df["posicion_norm"] = df["posicion_paciente"].map(_norm_topo_texto)
    df["pos_tubo_norm"] = df["pos_tubo"].map(_norm_topo_texto)
    df["examen_norm"] = df["examen"].map(_norm_topo_examen)
    df["nombre_imagen_norm"] = df["nombre_imagen"].map(_norm_topo_texto)
    df = df[(df["nombre_imagen_norm"] != "") & (df["examen_norm"] != "")]
    return df


def _reparar_nombre_zip(name):
    try:
        reparado = name.encode("cp437").decode("utf-8")
    except Exception:
        reparado = name
    return reparado

@st.cache_data
def cargar_indice_zip_topogramas():
    indice = {}
    if not ZIP_TOPOGRAMAS.exists():
        return indice
    with zipfile.ZipFile(ZIP_TOPOGRAMAS, "r") as zf:
        for name in zf.namelist():
            if name.endswith("/") or "__MACOSX" in name:
                continue
            name_ok = _reparar_nombre_zip(name)
            base = Path(name_ok).name
            stem = Path(base).stem
            indice[_norm_topo_texto(base)] = name
            indice[_norm_topo_texto(stem)] = name
    return indice


def obtener_imagen_topograma_adquirido(examen, posicion_paciente, entrada, pos_tubo):
    df = cargar_tabla_topogramas_adquiridos()
    if df.empty:
        return None, "No se pudo leer el Excel de topogramas."

    examen_norm = _norm_topo_examen(examen)
    posicion_norm = _norm_topo_texto(posicion_paciente)
    entrada_norm = _norm_topo_texto(entrada)
    tubo_norm = _norm_topo_texto(pos_tubo)

    candidatos = df[
        (df["examen_norm"] == examen_norm) &
        (df["posicion_norm"] == posicion_norm) &
        (df["entrada_norm"] == entrada_norm) &
        (df["pos_tubo_norm"] == tubo_norm)
    ]

    if candidatos.empty:
        # ayuda diagnóstica: permitir equivalencia ATC/angiotac y espacios raros
        return None, f"Sin coincidencia en Excel para examen='{examen}', posición='{posicion_paciente}', entrada='{entrada}', tubo='{pos_tubo}'."

    nombre = str(candidatos.iloc[0]["nombre_imagen"]).strip()
    indice_zip = cargar_indice_zip_topogramas()
    miembro = indice_zip.get(_norm_topo_texto(nombre))
    if miembro is None:
        return None, f"La imagen '{nombre}' no está dentro del ZIP."

    try:
        with zipfile.ZipFile(ZIP_TOPOGRAMAS, "r") as zf:
            with zf.open(miembro) as f:
                data = f.read()
        img = Image.open(io.BytesIO(data))
        return img, None
    except Exception as e:
        return None, f"No se pudo abrir la imagen '{nombre}': {e}"


# Carpeta con imágenes de posicionamiento para topograma
DIR_IMAGENES_TOPO_POS = IMAGES_DIR / "IMAGENES POSICIONAMIENTO TOPOGRAMA"
ZIP_IMAGENES_TOPO_POS = IMAGES_DIR / "IMAGENES POSICIONAMIENTO TOPOGRAMA.zip"
CACHE_IMAGENES_TOPO_POS = BASE_DIR / "_cache_imagenes_topograma"


def preparar_fuentes_imagenes_topograma():
    """
    Busca imágenes del topograma en tres lugares:
    1) archivos sueltos en la raíz del repositorio
    2) carpeta IMAGENES POSICIONAMIENTO TOPOGRAMA
    3) ZIP IMAGENES POSICIONAMIENTO TOPOGRAMA.zip extraído en caché
    """
    fuentes = []

    try:
        if BASE_DIR.exists():
            fuentes.append(BASE_DIR)

        if DIR_IMAGENES_TOPO_POS.exists():
            fuentes.append(DIR_IMAGENES_TOPO_POS)

        if ZIP_IMAGENES_TOPO_POS.exists():
            CACHE_IMAGENES_TOPO_POS.mkdir(parents=True, exist_ok=True)
            import zipfile
            with zipfile.ZipFile(ZIP_IMAGENES_TOPO_POS, "r") as zf:
                zf.extractall(CACHE_IMAGENES_TOPO_POS)

            interna = CACHE_IMAGENES_TOPO_POS / "IMAGENES POSICIONAMIENTO TOPOGRAMA"
            if interna.exists():
                fuentes.append(interna)
            else:
                fuentes.append(CACHE_IMAGENES_TOPO_POS)
    except Exception:
        pass

    fuentes_limpias = []
    vistos = set()
    for fuente in fuentes:
        try:
            clave = str(fuente.resolve())
        except Exception:
            clave = str(fuente)
        if clave not in vistos:
            vistos.add(clave)
            fuentes_limpias.append(fuente)

    return fuentes_limpias

def normalizar_posicion_topograma(posicion: str) -> str:
    posicion = (posicion or "").strip().lower()
    if "lateral derecho" in posicion:
        return "lateral_derecho"
    if "lateral izquierdo" in posicion:
        return "lateral_izquierdo"
    if "prono" in posicion:
        return "prono"
    if "supino" in posicion:
        return "supino"
    return ""


def normalizar_entrada_topograma(entrada: str) -> str:
    entrada = (entrada or "").strip().lower()
    if "cabeza" in entrada:
        return "cabeza_primero"
    if "pies" in entrada:
        return "pies_primero"
    return ""


def normalizar_tubo_topograma(pos_tubo: str) -> str:
    pos_tubo = (pos_tubo or "").strip().lower()
    if "arriba" in pos_tubo:
        return "arriba"
    if "abajo" in pos_tubo:
        return "abajo"
    if "derecha" in pos_tubo:
        return "derecho"
    if "izquierda" in pos_tubo:
        return "izquierdo"
    return ""


def normalizar_nombre_archivo_topograma(nombre: str) -> str:
    nombre = (nombre or "").lower().strip()
    reemplazos = {
        "á": "a", "é": "e", "í": "i", "ó": "o", "ú": "u", "ü": "u", "ñ": "n",
        "°": "", "º": "", "┬░": "", "decubito ": "",
        "lateral derecho": "lateral_derecho",
        "lateral izquierdo": "lateral_izquierdo",
        "derecha": "derecho",
        "izquierda": "izquierdo",
        "cabeza primero": "cabeza_primero",
        "pies primero": "pies_primero",
    }
    for a,b in reemplazos.items():
        nombre = nombre.replace(a,b)

    import re
    nombre = nombre.replace("__", "_")
    nombre = nombre.replace(" ", "_")
    nombre = re.sub(r'[^a-z0-9_]+', '_', nombre)
    nombre = re.sub(r'_+', '_', nombre).strip('_')

    # muchas imágenes vienen con arriba_0 o abajo_180; para comparar basta la dirección
    tokens = [t for t in nombre.split('_') if t]
    filtrados = []
    for t in tokens:
        if t.isdigit():
            continue
        filtrados.append(t)
    nombre = '_'.join(filtrados)
    nombre = nombre.replace('arriba_0', 'arriba').replace('abajo_180', 'abajo')
    return nombre


def obtener_imagen_posicionamiento_topograma(posicion: str, entrada: str, pos_tubo: str):
    entrada_norm = normalizar_entrada_topograma(entrada)
    posicion_norm = normalizar_posicion_topograma(posicion)
    tubo_norm = normalizar_tubo_topograma(pos_tubo)

    if not entrada_norm or not posicion_norm or not tubo_norm:
        return None

    objetivo_norm = normalizar_nombre_archivo_topograma(
        f"topograma_{entrada_norm}_{posicion_norm}_{tubo_norm}"
    )
    extensiones = {".png", ".jpg", ".jpeg", ".webp"}

    for fuente in preparar_fuentes_imagenes_topograma():
        if not fuente.exists():
            continue

        for ruta in fuente.rglob("*"):
            if not ruta.is_file():
                continue
            if ruta.suffix.lower() not in extensiones:
                continue
            nombre_lower = ruta.name.lower()
            if "__macosx" in nombre_lower or ruta.name.startswith("._") or ruta.name == ".DS_Store":
                continue
            if not nombre_lower.startswith("topograma"):
                continue

            stem_norm = normalizar_nombre_archivo_topograma(ruta.stem)
            if stem_norm == objetivo_norm:
                return ruta

    return None



# Imágenes de posición de corte para bolus
DIR_POSICION_CORTE = BASE_DIR / "POSICION DE CORTE"
ZIP_POSICION_CORTE = BASE_DIR / "POSICION DE CORTE.zip"
CACHE_POSICION_CORTE = BASE_DIR / "_cache_posicion_corte"


def preparar_fuentes_posicion_corte():
    fuentes = []
    try:
        if DIR_POSICION_CORTE.exists():
            fuentes.append(DIR_POSICION_CORTE)
        if ZIP_POSICION_CORTE.exists():
            CACHE_POSICION_CORTE.mkdir(parents=True, exist_ok=True)
            with zipfile.ZipFile(ZIP_POSICION_CORTE, "r") as zf:
                zf.extractall(CACHE_POSICION_CORTE)
            interna = CACHE_POSICION_CORTE / "POSICION DE CORTE"
            if interna.exists():
                fuentes.append(interna)
            else:
                fuentes.append(CACHE_POSICION_CORTE)
    except Exception:
        pass
    return fuentes


def _normalizar_posicion_corte(nombre: str) -> str:
    nombre = (nombre or "").strip().lower()
    nombre = unicodedata.normalize("NFKD", nombre).encode("ascii", "ignore").decode("ascii")
    nombre = nombre.replace("_", " ").replace("-", " ")
    nombre = " ".join(nombre.split())
    return nombre


def obtener_imagen_posicion_corte(nombre_posicion: str):
    objetivo = _normalizar_posicion_corte(nombre_posicion)
    extensiones = {".png", ".jpg", ".jpeg", ".webp"}
    for fuente in preparar_fuentes_posicion_corte():
        if not fuente.exists():
            continue
        for ruta in fuente.rglob("*"):
            if not ruta.is_file() or ruta.suffix.lower() not in extensiones:
                continue
            if ruta.name.startswith("._") or "__MACOSX" in str(ruta):
                continue
            if _normalizar_posicion_corte(ruta.stem) == objetivo:
                return ruta
    return None

