                        st.session_state["reconstrucciones_por_exp"][_exp_id].append(_copia_rec)
                        _reindexar_reconstrucciones(_exp_id)
                        _nuevo_id = st.session_state["reconstrucciones_por_exp"][_exp_id][-1]["id"]
